CREATE OR REPLACE FUNCTION fpa_kep_balance_by_kep_type (as_memno char,ai_seqn integer,ai_month integer,ai_year integer) RETURNS bigint AS $body$
DECLARE

  ldc_balance bigint;
  ldc_bal_lon bigint;
  ldc_unkeep bigint;
  ldc_unkeep_pri bigint;
  ldc_return bigint;
  ls_kep_code sc_kep_t_monthly_receive_det.keeping_type_code%type;
  ls_desc sc_kep_t_monthly_receive_det.receive_description%type;
  ldt_date timestamp(0);

BEGIN
 begin
  select  keeping_type_code
        , principal_balance_of_loan
        , unkeep_money_amount
        , receive_description
        , pka_srv_datetime.fp_lastdayofmonth(to_date('1/'||ai_month::text||'/'||ai_year::text,'dd/mm/yyyy'))
        , unkeep_principal_of_loan
        , money_return
  into STRICT    ls_kep_code
        , ldc_bal_lon
        , ldc_unkeep
        , ls_desc
        , ldt_date
        , ldc_unkeep_pri
        , ldc_return
  from    sc_kep_t_monthly_receive_det
  where (membership_no = as_memno)
  and (receive_month = ai_month)
  and (receive_year = ai_year)
  and (receive_seq = ai_seqn);
 exception
 when no_data_found then null;
 when others then CALL spa_dberror('select จาก kep det');
 end;
  if ldc_unkeep > 0 or ldc_return > 0  then
     if substr(trim(both ls_kep_code),1,2) = 'ML' then
        ldc_balance := pka_com_function.fp_lon_get_balance_atdate(trim(both ls_desc),ldt_date);
        if ldc_balance = 0 and ldc_unkeep > 0 then
           ldc_balance := ldc_unkeep_pri;
        end if;
     elsif substr(trim(both ls_kep_code),1,2) = 'MS' then
        ldc_balance := pka_com_function.fp_shr_get_balance_atdate(as_memno,ldt_date);
        if ldc_unkeep > 0  then
           ldc_balance := ldc_balance + ldc_unkeep;
        end if;
     else
        ldc_balance := ldc_bal_lon;
     end if;
  else
      ldc_balance := ldc_bal_lon;
  end if;

  return coalesce(ldc_balance,0);
exception when others then CALL spa_dberror('FPA_KEP_BALANCE_BY_KEP_TYPE');return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
